mapper.select:
/* FileMapper.selectListFileByFileId : 파일 ID로 파일 목록 조회 */ SELECT tf.file_id ,tf.sort_order ,tf.file_type_code ,tf.org_file_name ,tf.convert_file_name ,tf.file_path ,tf.file_size ,tf.create_at ,tf.create_id FROM tb_file tf
AND tf.file_id = #{fileId} AND tf.delete_yn = 'N'
ORDER BY tf.sort_order ASC, tf.create_at ASC
